import { Task, TaskStatus } from '../types/task';

/**
 * Execution Engine for Hierarchical Workflow Graphs
 */

/**
 * Recomputes statuses for the entire graph based on hierarchical and dependency rules.
 * 
 * Rules:
 * 1. A task is DONE if:
 *    - It has no subtasks AND its status is manually set to DONE.
 *    - It has subtasks AND ALL its subtasks are DONE.
 * 2. A task is READY if:
 *    - Its status is NOT DONE.
 *    - All its dependencies (dependency_task_id) are DONE.
 * 3. A task is BLOCKED if:
 *    - Any of its dependencies (dependency_task_id) are NOT DONE.
 * 4. A task is IN_PROGRESS if:
 *    - It is READY and has been manually set to RUNNING.
 */
export function recomputeTaskStatuses(tasks: Task[]): Task[] {
    const taskMap = new Map<string, Task>(tasks.map(t => [t.id, t]));

    // Group subtasks key: parent_id, val: children[]
    const parentToChildren = new Map<string, Task[]>();
    tasks.forEach(t => {
        if (t.parent_id) {
            const children = parentToChildren.get(t.parent_id) || [];
            children.push(t);
            parentToChildren.set(t.parent_id, children);
        }
    });

    // 1. Recursive status resolution for parents
    const resolveStatus = (t: Task): TaskStatus => {
        const children = parentToChildren.get(t.id);

        // Rule: If it's a parent task with children
        if (children && children.length > 0) {
            const allDone = children.every(c => c.status === 'DONE');
            if (allDone) return 'DONE';

            const anyStarted = children.some(c => c.status === 'RUNNING' || c.status === 'DONE');
            if (anyStarted) return 'RUNNING';

            const anyReady = children.some(c => c.status === 'READY');
            return anyReady ? 'READY' : 'BLOCKED';
        }

        // Rule: For executable tasks (subtasks or standalone tasks)
        if (t.status === 'DONE') return 'DONE';
        if (t.status === 'RUNNING') return 'RUNNING' as TaskStatus;

        // Rule: Parent Inheritance - subtasks act as prerequisites to their parent's dependencies
        if (t.parent_id) {
            const parent = taskMap.get(t.parent_id);
            if (parent && parent.depends_on && parent.depends_on.length > 0) {
                const parentDepsDone = parent.depends_on.every(pid => taskMap.get(pid)?.status === 'DONE');
                if (!parentDepsDone) return 'BLOCKED';
            }
        }

        // Rule: Local Dependency Check
        const deps = t.depends_on || [];
        if (deps.length === 0) return 'READY';

        const allDepsDone = deps.every(depId => {
            const dep = taskMap.get(depId);
            return dep?.status === 'DONE';
        });

        return allDepsDone ? 'READY' : 'BLOCKED';
    };

    // Calculate updated set (parents computed after their children naturally in a single pass if no recursion, 
    // but we use resolveStatus logic above)
    return tasks.map(t => ({
        ...t,
        status: resolveStatus(t)
    }));
}

/**
 * Computes the topological order for execution.
 * Returns tasks sorted by their execution priority based on the graph.
 */
export function computeTopologicalOrder(tasks: Task[]): Task[] {
    const visited = new Set<string>();
    const recStack = new Set<string>();
    const result: Task[] = [];
    const taskMap = new Map<string, Task>(tasks.map(t => [t.id, t]));

    function visit(task: Task) {
        if (visited.has(task.id)) return;
        if (recStack.has(task.id)) {
            console.warn(`Topological Sort: Cycle detected at task ${task.id}. Execution order may be unstable.`);
            return;
        }

        recStack.add(task.id);

        // Visit dependencies first
        const deps = task.depends_on || [];
        deps.forEach(depId => {
            const dep = taskMap.get(depId);
            if (dep) visit(dep);
        });

        recStack.delete(task.id);
        visited.add(task.id);
        result.push(task);
    }

    // Sort by graph_order as secondary priority
    const sortedSeeds = [...tasks].sort((a, b) => (a.graph_order || 0) - (b.graph_order || 0));
    sortedSeeds.forEach(t => visit(t));

    return result;
}
